// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}


// Helper function to get weather icon/emoji based on condition
function getWeatherIcon(condition: string): string {
  const normalizedCondition = condition.toLowerCase();
  if (normalizedCondition.includes('sunny') || normalizedCondition.includes('clear')) return '☀️';
  if (normalizedCondition.includes('cloudy')) return '☁️';
  if (normalizedCondition.includes('rainy') || normalizedCondition.includes('rain')) return '🌧️';
  if (normalizedCondition.includes('snowy') || normalizedCondition.includes('snow')) return '❄️';
  if (normalizedCondition.includes('stormy') || normalizedCondition.includes('storm')) return '⛈️';
  if (normalizedCondition.includes('windy') || normalizedCondition.includes('wind')) return '💨';
  if (normalizedCondition.includes('foggy') || normalizedCondition.includes('fog')) return '🌫️';
  return '🌤️';
}

export default function Component(props: Props) {
  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)" align="center">
        {/* Header with city and current weather */}
        <Stack align="center" gap="var(--ggui-spacing-2)">
          <Heading level={2}>{props.city}</Heading>
          <Box style={{ fontSize: '48px' }}>{getWeatherIcon(props.condition)}</Box>
        </Stack>

        {/* Current temperature card */}
        <Card shadow="md" padding="var(--ggui-spacing-8)" radius="lg">
          <Stack align="center" gap="var(--ggui-spacing-4)">
            <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600)">{props.temperature}°{props.unit}</Text>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">{props.condition}</Text>
          </Stack>
        </Card>

        {/* Humidity and Wind Speed row */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-4)" align="stretch">
          <Card shadow="sm" padding="var(--ggui-spacing-4)" radius="md" style={{ flex: 1 }}>
            <Stack align="center" gap="var(--ggui-spacing-2)">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
              <Text size="2xl" weight="semibold">{props.humidity}%</Text>
            </Stack>
          </Card>
          <Card shadow="sm" padding="var(--ggui-spacing-4)" radius="md" style={{ flex: 1 }}>
            <Stack align="center" gap="var(--ggui-spacing-2)">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
              <Text size="2xl" weight="semibold">{props.windSpeed} m/s</Text>
            </Stack>
          </Card>
        </Stack>

        {/* 5-day forecast strip */}
        <Stack gap="var(--ggui-spacing-2)">
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">5-Day Forecast</Text>
          <Stack direction="horizontal" gap="var(--ggui-spacing-2)" wrap>
            {props.forecast && props.forecast.length > 0 ? (
              props.forecast.map((day, index) => (
                <Card key={index} shadow="sm" padding="var(--ggui-spacing-2)" radius="md" style={{ flex: '0 0 auto', minWidth: '100px', textAlign: 'center' }}>
                  <Stack align="center" gap="var(--ggui-spacing-1)">
                    <Text variant="caption" weight="semibold">{day.day || 'Day'}</Text>
                    <Box style={{ fontSize: '24px' }}>{day.icon ? getWeatherIcon(day.icon) : '🌤️'}</Box>
                    <Stack direction="horizontal" gap="var(--ggui-spacing-1)" justify="center">
                      <Text variant="caption"><span style={{ color: 'var(--ggui-color-success-600)' }}>{day.high}°{props.unit}</span></Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{day.low}°{props.unit}</Text>
                    </Stack>
                  </Stack>
                </Card>
              ))
            ) : (
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">No forecast data available</Text>
            )}
          </Stack>
        </Stack>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };


// Helper function to validate email format
function isValidEmail(email: string): boolean {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
}

// Helper function to validate required text fields
function isValidName(name: string): boolean {
  return name.trim().length > 0;
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State management
  const [currentStep, setCurrentStep] = useState<number>(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 0,
    features: [] as string[],
    comments: '',
  });
  const [errors, setErrors] = useState({ name: '', email: '', satisfaction: '', features: '' });

  // Validation helpers
  const validateStep1 = useCallback((): boolean => {
    const newErrors = { name: '', email: '' };
    let isValid = true;

    if (!isValidName(formData.name)) {
      newErrors.name = 'Name is required';
      isValid = false;
    }
    if (!isValidEmail(formData.email)) {
      newErrors.email = 'Please enter a valid email address';
      isValid = false;
    }
    setErrors(newErrors);
    return isValid;
  }, [formData.name, formData.email]);

  // Step progression handlers
  const handleNext = useCallback(() => {
    if (currentStep === 1) {
      if (!validateStep1()) return;
    }
    if (currentStep === 2) {
      if (formData.satisfaction === 0) {
        setErrors((e) => ({ ...e, satisfaction: 'Please select a satisfaction level' }));
        return;
      }
    }
    if (currentStep === 3) {
      if (formData.features.length === 0) {
        setErrors((e) => ({ ...e, features: 'Please select at least one feature' }));
        return;
      }
    }
    if (currentStep < 4) {
      setCurrentStep(currentStep + 1);
    }
  }, [currentStep, validateStep1, formData]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  const handleSubmit = useCallback(() => {
    if (validateStep1()) {
      submit({
        name: formData.name,
        email: formData.email,
        satisfaction: formData.satisfaction,
        features: formData.features,
        comments: formData.comments,
      });
    }
  }, [formData, validateStep1, submit]);

  const isStep1Valid = isValidName(formData.name) && isValidEmail(formData.email);
  const isStep2Valid = formData.satisfaction !== 0;
  const isStep3Valid = formData.features.length > 0;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Progress Bar */}
        <Stack gap="var(--ggui-spacing-2)">
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {currentStep} of 4
          </Text>
          <Progress value={currentStep} max={4} size="md" />

        {/* Step 1: Name and Email */}
        {currentStep === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>Your Information</Heading>
              <Stack gap="var(--ggui-spacing-4)">
                <Input
                  label="Name"
                  required
                  value={formData.name}
                  onChange={(value) => {
                    setFormData({ ...formData, name: value });
                    if (errors.name) setErrors({ ...errors, name: '' });
                  }}
                  error={errors.name}
                  placeholder="Enter your full name"
                />
                <Input
                  label="Email"
                  type="email"
                  required
                  value={formData.email}
                  onChange={(value) => {
                    setFormData({ ...formData, email: value });
                    if (errors.email) setErrors({ ...errors, email: '' });
                  }}
                  error={errors.email}
                  placeholder="Enter your email address"
                />
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {/* Step 2: Satisfaction Rating */}
        {currentStep === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>How satisfied are you?</Heading>
              <RadioGroup
                label="Satisfaction Level"
                value={String(formData.satisfaction)}
                onChange={(value) => {
                  setFormData({ ...formData, satisfaction: parseInt(value) });
                  if (errors.satisfaction) setErrors({ ...errors, satisfaction: '' });
                }}
                options={props.satisfactionLabels.map((label, idx) => ({
                  value: String(idx + 1),
                  label,
                }))}
                direction="vertical"
                error={errors.satisfaction}
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {currentStep === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>Which features interest you?</Heading>
              {errors.features && (
                <Alert variant="error">{errors.features}</Alert>
              )}
              <Stack gap="var(--ggui-spacing-2)">
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={formData.features.includes(feature)}
                    onChange={(checked) => {
                      setFormData({
                        ...formData,
                        features: checked
                          ? [...formData.features, feature]
                          : formData.features.filter((f) => f !== feature),
                      });
                      if (errors.features) setErrors({ ...errors, features: '' });
                    }}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {currentStep === 4 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>Additional Comments</Heading>
              <Stack gap="var(--ggui-spacing-4)">
                <TextArea
                  label="Comments"
                  value={formData.comments}
                  onChange={(value) => setFormData({ ...formData, comments: value.slice(0, 500) })}
                  maxLength={500}
                  showCount
                  rows={6}
                  placeholder="Please share any additional feedback (optional)"
                />
              </Stack>
            </Stack>
          </Card>
        )}
        {/* Navigation Buttons */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-4)" justify="between" align="center">
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          {currentStep < 4 ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={
                (currentStep === 1 && !isStep1Valid) ||
                (currentStep === 2 && !isStep2Valid) ||
                (currentStep === 3 && !isStep3Valid)
              }
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleSubmit}
            >
              Submit
            </Button>
          )}
        </Stack>
          {currentStep < 5 ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={currentStep === 1 && !isStep1Valid}
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleSubmit}
            >
              Submit
            </Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column?: string; title?: string; assignee?: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };



// Task state management and handlers
function getTasksByColumn(tasks: Props['tasks'], columnId: string) {
  return tasks.filter(task => task.column === columnId) || [];
}

function getInitials(name?: string): string {
  if (!name) return '?';
  return name
    .split(' ')
    .map(word => word[0]?.toUpperCase())
    .join('')
    .slice(0, 2);
}

function getPriorityColor(priority?: string): string {
  switch (priority) {
    case 'high':
      return 'var(--ggui-color-error-500, #ef4444)';
    case 'medium':
      return 'var(--ggui-color-warning-500, #f59e0b)';
    case 'low':
      return 'var(--ggui-color-success-500, #22c55e)';
    default:
      return 'var(--ggui-color-outline, #d4d4d8)';
  }
}

function getPriorityVariant(priority?: string): 'error' | 'warning' | 'success' | 'default' {
  switch (priority) {
    case 'high':return 'error';
    case 'medium': return 'warning';
    case 'low': return 'success';
    default: return 'default';
  }
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // Local state for UI
  const [localTasks, setLocalTasks] = useState<Props['tasks']>(props.tasks);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState<string>('');
  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState<string>('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  // Update local tasks from props
  useEffect(() => {
    setLocalTasks(props.tasks);
  }, [props.tasks]);

  // Apply stream updates
  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (!task?.id) return;

      setLocalTasks(prevTasks => {
        if (action === 'delete') {
          return prevTasks.filter(t => t.id !== task.id);
        }
        const exists = prevTasks.some(t => t.id === task.id);
        if (exists) {
          return prevTasks.map(t => (t.id === task.id ? task : t));
        }
        return [...prevTasks, task];
      });
    }
  }, [taskChanged.latest]);

  const handleMoveTask = useCallback(
    (taskId: string, newColumn: string) => {
      setLocalTasks(prev =>
        prev.map(t => (t.id === taskId ? { ...t, column: newColumn } : t))
      );
      taskUpdate({
        action: 'move',
        taskId,
        data: { column: newColumn },
      });
    },
    [taskUpdate]
  );

  const handleEditTask = useCallback(
    (taskId: string, newTitle: string) => {
      setLocalTasks(prev =>
        prev.map(t => (t.id === taskId ? { ...t, title: newTitle } : t))
      );
      taskUpdate({
        action: 'edit',
        taskId,
        data: { title: newTitle },
      });
      setEditingTaskId(null);
    },
    [taskUpdate]
  );

  const handleAddTask = useCallback(
    (columnId: string, title: string, priority: 'low' | 'medium' | 'high') => {
      if (!title.trim()) return;
      const newId = `task-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
      const newTask = { id: newId, title, priority, column: columnId, assignee: undefined };
      setLocalTasks(prev => [...prev, newTask]);
      taskUpdate({
        action: 'create',
        taskId: newId,
        data: { column: columnId, title, assignee: undefined },
      });
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setAddingToColumn(null);
    },
    [taskUpdate]
  );

  // Computed: total and completed tasks
  const totalTasks = localTasks.length;
  const completedTasks = getTasksByColumn(localTasks, 'done').length;


  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary Bar */}
        <Card shadow="sm" padding="var(--ggui-spacing-4)">
          <Stack direction="horizontal" justify="between" align="center">
            <Stack direction="horizontal" gap="var(--ggui-spacing-4)" align="center">
              <Heading level={3} color="var(--ggui-color-onSurface)">Task Board</Heading>
              <Badge variant="primary" size="sm">{totalTasks} tasks</Badge>
              <Badge variant="success" size="sm">{completedTasks} completed</Badge>
            </Stack>
            <Progress value={totalTasks > 0 ? (completedTasks / totalTasks) * 100 : 0} max={100} variant="success" size="sm" />
          </Stack>
        </Card>

        {/* Kanban Columns */}
        {/* Kanban Columns */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-4)" align="start">
          {props.columns.map(column => {
            if (!column.id) return null;
            const columnTasks = getTasksByColumn(localTasks, column.id);
            return (
              <Card
                key={column.id}
                shadow="none"
                border={true}
                padding="var(--ggui-spacing-4)"
                style={{ flex: '1 1 300px', minHeight: '600px', display: 'flex', flexDirection: 'column' }}
              >
                {/* Column Header */}
                <Stack gap="var(--ggui-spacing-2)" style={{ marginBottom: 'var(--ggui-spacing-4)' }}>
                  <Row justify="between" align="center">
                    <Heading level={4} color="var(--ggui-color-onSurface)">{column.name}</Heading>
                    <Badge variant="secondary" size="sm">{columnTasks.length}</Badge>
                  </Row>
                  <Divider orientation="horizontal" margin="0" />
                </Stack>

                {/* Task List */}
                <Stack
                  gap="var(--ggui-spacing-3)"
                  style={{ flex: 1, overflowY: 'auto', marginBottom: 'var(--ggui-spacing-4)' }}
                >
                  {columnTasks.map(task => (
                    <Card
                      key={task.id}
                      shadow="sm"
                      padding="var(--ggui-spacing-3)"
                      border={true}
                      style={{ cursor: 'grab' }}
                    >
                      <Stack gap="var(--ggui-spacing-2)">
                        {/* Task Title (Editable) */}
                        <Row justify="between" align="center" gap="var(--ggui-spacing-2)">
                          {editingTaskId === task.id ? (
                            <Input
                              label="Task title"
                              value={editingTitle}
                              onChange={setEditingTitle}
                              placeholder="Enter task title"
                              size="sm"
                            />
                          ) : (
                            <Text
                              variant="body"
                              as={Clickable}
                              onClick={() => {
                                setEditingTaskId(task.id || null);
                                setEditingTitle(task.title || '');
                              }}
                              style={{ cursor: 'pointer', padding: '4px 0', flex: 1 }}
                            >
                              {task.title || 'Untitled'}
                            </Text>
                          )}
                          {!editingTaskId && task.id && (
                            <Button
                              size="xs"
                              variant="ghost"
                              rightIcon={<Icon name="edit" size={14} />}
                              onClick={() => {
                                setEditingTaskId(task.id || null);
                                setEditingTitle(task.title || '');
                              }}
                            >
                              Edit
                            </Button>
                          )}
                        </Row>

                        {/* Priority Badge */}
                        {task.priority && (
                          <Badge variant={getPriorityVariant(task.priority)} size="sm">
                            {task.priority}
                          </Badge>
                        )}

                        {/* Assignee & Due Date Row */}
                        <Row justify="between" align="center" gap="var(--ggui-spacing-2)">
                          <Tooltip content={task.assignee || 'Unassigned'} position="top">
                            <Avatar name={task.assignee || 'Unassigned'} size={24} shape="circle" />
                          </Tooltip>
                          {task.dueDate && (
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" size="xs">
                              {new Date(task.dueDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                            </Text>
                          )}
                        </Row>

                        {/* Edit & Move Controls */}
                        <Row justify="between" gap="var(--ggui-spacing-2)" style={{ marginTop: 'var(--ggui-spacing-1)' }}>
                          {editingTaskId === task.id && (
                            <Button
                              size="xs"
                              variant="primary"
                              onClick={() => handleEditTask(task.id || '', editingTitle)}
                            >
                              Save
                            </Button>
                          )}
                          {!editingTaskId && task.id && (
                            <Dropdown
                              trigger={<Button size="xs" variant="ghost" rightIcon={<Icon name="chevron-down" size={16} />}>Move</Button>}
                              options={props.columns
                                .filter(col => col.id !== task.column)
                                .map(col => ({
                                  value: col.id || '',
                                  label: col.name || '',
                                })) || []}
                              value={task.column || ''}
                              onChange={val => handleMoveTask(task.id || '', val)}
                            />
                          )}
                        </Row>
                      </Stack>
                    </Card>
                  ))}
                </Stack>

                {/* Add Task Section */}
                {addingToColumn === column.id ? (
                  <Card shadow="none" padding="var(--ggui-spacing-3)" border={true} style={{ borderStyle: 'dashed' }}>
                    <Stack gap="var(--ggui-spacing-2)">
                      <Input
                        label="Task title"
                        value={newTaskTitle}
                        onChange={setNewTaskTitle}
                        placeholder="New task name"
                        size="sm"
                      />
                      <Select
                        label="Priority"
                        value={newTaskPriority}
                        onChange={val => setNewTaskPriority(val as 'low' | 'medium' | 'high')}
                        options={[
                          { value: 'low', label: 'Low' },
                          { value: 'medium', label: 'Medium' },
                          { value: 'high', label: 'High' },
                        ]}
                        size="sm"
                      />
                      <Row gap="var(--ggui-spacing-2)" justify="end">
                        <Button
                          size="xs"
                          variant="ghost"
                          onClick={() => {
                            setAddingToColumn(null);
                            setNewTaskTitle('');
                            setNewTaskPriority('medium');
                          }}
                        >
                          Cancel
                        </Button>
                        <Button
                          size="xs"
                          variant="primary"
                          onClick={() => handleAddTask(column.id || '', newTaskTitle, newTaskPriority)}
                        >
                          Add
                        </Button>
                      </Row>
                    </Stack>
                  </Card>
                ) : (
                  <Button
                    fullWidth
                    variant="outline"
                    size="sm"
                    onClick={() => setAddingToColumn(column.id || '')}
                    leftIcon={<Icon name="plus" size={16} />}
                  >
                    Add Task
                  </Button>
                )}
              </Card>
            );
          })}
        </Stack>
      </Stack>
    </Container>
  );
}

