  }, [searchQuery, props.elements]);

  // Get unique categories and their colors using a deterministic mapping
  const categoryColors = useMemo(() => {
    const categories = new Set<string>();
    props.elements.forEach((el) => {
      if (el.category) categories.add(el.category);
    });

    const colorMap: Record<string, string> = {
      'noble-gas': 'var(--ggui-color-info-50, #ecfeff)',
      'halogen': 'var(--ggui-color-warning-50, #fffbeb)',
      'alkali-metal': 'var(--ggui-color-primary-50, #f0f9ff)',
      'alkaline-earth-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
      'transition-metal': 'var(--ggui-color-success-50, #f0fdf4)',
      'lanthanide': 'var(--ggui-color-warning-100, #fef3c7)',
      'actinide': 'var(--ggui-color-error-50, #fef2f2)',
      'metalloid': 'var(--ggui-color-success-100, #dcfce7)',
      'nonmetal': 'var(--ggui-color-primary-200, #bae6fd)',
      'other': 'var(--ggui-color-surfaceVariant, #f4f4f5)',
    };

    return Array.from(categories).reduce((acc, cat) => {
      acc[cat] = colorMap[cat] || 'var(--ggui-color-surfaceVariant, #f4f4f5)';
      return acc;
    }, {} as Record<string, string>);
  }, [props.elements]);

  // Get unique categories for legend
  const categories = useMemo(() => {
    const cats = new Set<string>();
    props.elements.forEach((el) => {
      if (el.category) cats.add(el.category);
    });
    return Array.from(cats).sort();
  }, [props.elements]);

  return (
    <Container maxWidth="xl" padding={24}>
