                    onKeyDown={(e: React.KeyboardEvent) => {
                      if (e.key === 'Enter' || e.key === ' ') {
                        e.preventDefault();
                        setSelectedElement(element);
                      }
                    }}
                    aria-label={`${element.name} (${element.symbol}), atomic number ${element.atomicNumber}, category ${element.category}`}
