            </Stack>
          </Card>
        )}

        {/* Element Details Panel */}
        {selectedElement && (
          <Card shadow="md" padding="var(--ggui-spacing-4)">
            <Stack gap="var(--ggui-spacing-4)" align="stretch">
              <Box style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                <Heading level={3}>Element Details</Heading>
                <Button
                  variant="ghost"
                  size="sm"
