                >
                  Close
                </Button>
              </Box>
              <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />
                <Stack direction="horizontal" gap={24} align="start" wrap={false}>
                <Box style={{ flex: '0 0 auto' }}>
                  <Box
                    style={{
                      backgroundColor: selectedElement.category ? categoryColors[selectedElement.category] || 'var(--ggui-color-surfaceVariant, #f4f4f5)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      border: '2px solid var(--ggui-color-primary-600, #0284c7)',
                      borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                      padding: 'var(--ggui-spacing-6)',
                      display: 'flex',
                      flexDirection: 'column',
                      alignItems: 'center',
                      justifyContent: 'center',
                      minWidth: '120px',
                      minHeight: '120px',
                      position: 'relative',
                    }}
                  >
                    <Text
                      variant="label"
                      size="sm"
                      weight="semibold"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      style={{ position: 'absolute', top: 'var(--ggui-spacing-2)', left: 'var(--ggui-spacing-2)' }}
                    >
                      {selectedElement.atomicNumber}
                    </Text>
                    <Text
                      variant="body"
                      size="3xl"
                      weight="bold"
                      color="var(--ggui-color-onSurface, #18181b)"
