                    >
                      {selectedElement.symbol}
                    </Text>
                  </Box>
                </Box>
                <Stack gap={12} align="stretch" style={{ flex: '1 1 auto' }}>
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)" size="sm">
