                      background: isCurrentUser ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      maxWidth: '60%',
                    }}
                  >
                    <Text color={isCurrentUser ? 'white' : 'var(--ggui-color-onSurface, #18181b)'} variant="body">
                      {msg.text}
                    </Text>
                    {msg.timestamp && (
                      <Text color={isCurrentUser ? 'rgba(255,255,255,0.7)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'} variant="caption" style={{ marginTop: 'var(--ggui-spacing-1)', display: 'block' }}>
                        {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                      </Text>
                    )}
                  </Card>
                </div>
              </div>
            );
          })}
          {typingUser && (
            <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-2)' }}>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" is="span">{typingUser} is typing</Text>
              <Spinner size={16} color="var(--ggui-color-onSurfaceVariant, #52525b)" />
            </div>
          )}
          <div ref={messagesEndRef} />
        </Stack>
      </div>

      {/* Input Area */}
      <Card shadow="sm" padding="var(--ggui-spacing-4)" radius="md">
        <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
           <Input
             label=""
             placeholder="Type a message..."
             value={inputValue}
             onChange={setInputValue}
