                  }}
                >
                  <Text size="2xl">{emoji}</Text>
                </Card>
              ))}
            </Stack>
          </Stack>
        </Stack>
      </Card>
    )}

    {/* Step 2: Preferences */}
    {currentStep === 2 && (
      <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg" style={{ width: '100%', maxWidth: '500px' }}>
        <Stack gap="var(--ggui-spacing-6)">
          <Heading level={4}>Preferences</Heading>

          {/* Role Selection */}
          <Stack gap="var(--ggui-spacing-2)">
            <Select
              label="Role"
              required
              value={formData.role}
              onChange={(value) => setFormData({ ...formData, role: value })}
              options={props.roleOptions.map((role) => ({ value: role, label: role }))}
              placeholder="Select your role"
              error={errors.role}
            />
          </Stack>

          {/* Notification Toggle */}
          <Stack gap="var(--ggui-spacing-2)">
            <Toggle
              label="Email Notifications"
              checked={formData.emailNotifications}
              onChange={(checked) => setFormData({ ...formData, emailNotifications: checked })}
              size="md"
            />
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Receive email updates about your account
            </Text>
          </Stack>

          {/* Theme Preference */}
          <Stack gap="var(--ggui-spacing-2)">
            <Toggle
              label="Dark Theme"
              checked={formData.theme === 'dark'}
              onChange={(checked) => setFormData({ ...formData, theme: checked ? 'dark' : 'light' })}
              size="md"
            />
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Use dark mode for your interface
            </Text>
          </Stack>
        </Stack>
      </Card>
    )}

    {/* Step 3: Review & Confirm */}
    {currentStep === 3 && (
      <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg" style={{ width: '100%', maxWidth: '500px' }}>
        <Stack gap="var(--ggui-spacing-6)">
          <Heading level={4}>Review & Confirm</Heading>

          <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-md, 8px)">
            <Stack gap="var(--ggui-spacing-4)">
              <Stack gap="var(--ggui-spacing-1)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name</Text>
                <Text variant="body">{formData.name}</Text>
              </Stack>
              <Divider />

              <Stack gap="var(--ggui-spacing-1)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email</Text>
                <Text variant="body">{formData.email}</Text>
              </Stack>
              <Divider />

              <Stack gap="var(--ggui-spacing-1)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Avatar</Text>
                <Text variant="body" size="xl">{formData.avatar}</Text>
              </Stack>
              <Divider />

              <Stack gap="var(--ggui-spacing-1)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Role</Text>
                <Text variant="body">{formData.role}</Text>
              </Stack>
              <Divider />

              <Stack gap="var(--ggui-spacing-1)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email Notifications</Text>
                <Badge variant={formData.emailNotifications ? 'success' : 'secondary'}>
                  {formData.emailNotifications ? 'Enabled' : 'Disabled'}
                </Badge>
              </Stack>
              <Divider />

              <Stack gap="var(--ggui-spacing-1)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Theme</Text>
                <Badge variant="primary">
                  {formData.theme === 'dark' ? 'Dark' : 'Light'}
                </Badge>
              </Stack>
            </Stack>
          </Box>
        </Stack>
      </Card>
    )}

    {/* Navigation Buttons */}
    <Stack direction="horizontal" gap="var(--ggui-spacing-4)" justify="center" style={{ width: '100%', maxWidth: '500px' }}>
      {currentStep > 1 && (
        <Button variant="ghost" onClick={handleBack}>
          Back
        </Button>
      )}
      {currentStep < 3 && (
        <Button variant="primary" onClick={handleNext} disabled={currentStep === 1 ? !isStep1Valid() : !isStep2Valid()}>
          Next
        </Button>
      )}
      {currentStep === 3 && (
        <Button variant="primary" onClick={handleComplete}>
          Complete Setup
        </Button>
      )}
    </Stack>
  </Stack>
</Container>

  );
}
